lt(0) // Current measured value\n  country             String? // Null = global\n  dataSource          String // LAT, Salesforce, Survey, Manual, Combined\n  collectionFrequency String               @default(\"Monthly\") // Weekly, Monthly, Quarterly, Annually\n  isPrimary           Boolean              @default(false) // Primary KPIs are reported to executive review\n  evidenceRequired    Boolean              @default(true) // Whether evidence documentation is required\n  rfpReference        String? // Link to RFP requirement\n  owner               String? // Person responsible for measurement\n  lastMeasuredAt      DateTime?\n  nextMeasurementDue  DateTime?\n  status              String               @default(\"Active\") // Active, Paused, Achieved, Discontinued\n  measurements        OutcomeMeasurement[]\n  createdAt           DateTime             @default(now())\n  updatedAt           DateTime             @updatedAt\n}\n\nmodel OutcomeMeasurement {\n  id              String     @id @default(cuid())\n  kpiId           String\n  kpi             OutcomeKPI @relation(fields: [kpiId], references: [id], onDelete: Cascade)\n  measuredValue   Float\n  measurementDate DateTime   @default(now())\n  period          String // Week1..Week52, Month1..Month12, Q1..Q4, Year1\n  measuredBy      String\n  methodology     String? // How the measurement was taken\n  evidenceIds     String? // JSON array of EvidenceCapture IDs\n  confidence      Float      @default(1.0) // Confidence level 0-1\n  notes           String?\n  isVerified      Boolean    @default(false)\n  verifiedBy      String?\n  verifiedAt      DateTime?\n  createdAt       DateTime   @default(now())\n  updatedAt       DateTime   @updatedAt\n}\n\nmodel ReportingTemplate {\n  id              String    @id @default(cuid())\n  templateName    String\n  templateType    String // OutcomeReview, ExecutiveSummary, AdoptionReport, EffectivenessReport, DataQualityReport, ComplianceReport\n  description     String\n  country         String? // Null = all countries\n  sections        String // JSON array of template sections with field definitions\n  frequency       String    @default(\"Quarterly\") // Monthly, Quarterly, SemiAnnual, Annual, OneTime\n  audience        String // Executive, CountryManager, FieldOfficer, Stakeholder, Auditor\n  status          String    @default(\"Draft\") // Draft, Approved, Active, Archived\n  version         Int       @default(1)\n  approvedBy      String?\n  approvedAt      DateTime?\n  lastGeneratedAt DateTime?\n  generatedCount  Int       @default(0)\n  createdAt       DateTime  @default(now())\n  updatedAt       DateTime  @updatedAt\n}\n\nmodel ContinuousImprovement {\n  id                  String    @id @default(cuid())\n  title               String\n  description         String\n  category            String // Process, Technology, Training, Data, Integration, UserExperience, Compliance, Performance\n  source              String // IncidentReview, UserFeedback, Audit, KPIGap, StakeholderRequest, Assessment, BestPractice\n  priority            String    @default(\"Normal\") // Low, Normal, High, Urgent\n  status              String    @default(\"Identified\") // Identified, Analyzed, Proposed, Approved, InProgress, Implemented, Verified, Closed\n  impact              String    @default(\"Medium\") // Low, Medium, High, Transformative\n  effortEstimate      String? // Small, Medium, Large, ExtraLarge\n  country             String? // Null = all countries\n  relatedKpiId        String? // Link to OutcomeKPI\n  relatedIncidentId   String? // Link to IncidentResponse\n  relatedDefectId     String? // Link to DefectReport\n  proposedBy          String\n  assignedTo          String?\n  targetDate          DateTime?\n  completedDate       DateTime?\n  expectedBenefit     String?\n  actualBenefit       String?\n  implementationNotes String?\n  verificationMethod  String?\n  verifiedBy          String?\n  verifiedAt          DateTime?\n  createdAt           DateTime  @default(now())\n  updatedAt           DateTime  @updatedAt\n}\n\nmodel ExecutiveReviewPack {\n  id               String    @id @default(cuid())\n  packName         String\n  period           String // Q1-2025, Q2-2025, H1-2025, Year-2025\n  country          String? // Null = global\n  status           String    @default(\"Draft\") // Draft, InReview, Approved, Published, Archived\n  generatedAt      DateTime?\n  generatedBy      String?\n  reviewedBy       String?\n  reviewedAt       DateTime?\n  approvedBy       String?\n  approvedAt       DateTime?\n  sections         String? // JSON array of included sections with data\n  kpiSummary       String? // JSON KPI summary data\n  highlights       String? // JSON array of key highlights\n  risks            String? // JSON array of risks and mitigations\n  recommendations  String? // JSON array of recommendations\n  actionItems      String? // JSON array of follow-up action items\n  audience         String    @default(\"Executive\") // Executive, Board, Stakeholder, Donor\n  distributionList String? // JSON array of recipients\n  isPublished      Boolean   @default(false)\n  publishedAt      DateTime?\n  notes            String?\n  createdAt        DateTime  @default(now())\n  updatedAt        DateTime  @updatedAt\n}\n\nmodel EvidenceCapture {\n  id                         String    @id @default(cuid())\n  evidenceType               String // DataPoint, Screenshot, Testimonial, Report, Metric, AuditTrail, CaseStudy, SurveyResult\n  title                      String\n  description                String\n  category                   String // Adoption, Efficiency, Quality, Satisfaction, Impact, Compliance, Financial\n  country                    String? // Null = all countries\n  sourceSystem               String // LAT, Salesforce, Survey, Manual, External\n  evidenceData               String? // JSON with evidence payload (metrics, text, file references)\n  collectedBy                String\n  collectedAt                DateTime  @default(now())\n  relatedKpiId               String? // Link to OutcomeKPI\n  relatedReportingTemplateId String? // Link to ReportingTemplate\n  verificationStatus         String    @default(\"Pending\") // Pending, Verified, Rejected\n  verifiedBy                 String?\n  verifiedAt                 DateTime?\n  expiryDate                 DateTime? // When this evidence is no longer valid\n  isArchived                 Boolean   @default(false)\n  archivedAt                 DateTime?\n  notes                      String?\n  createdAt                  DateTime  @default(now())\n  updatedAt                  DateTime  @updatedAt\n}\n",
